// Embedded daily content generator
const today = new Date();
const dayOfWeek = today.getDay();
const dayName = today.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' });

// Encouragement
const encouragements = [
  "You are building something real. Keep stacking wins. Every small action compounds.",
  "Every 'no' gets you closer to the 'yes' that changes everything. Stay in the game.",
  "Discipline beats motivation every time. Show up anyway. The results follow.",
  "Small steps compound. What you do today matters more than you think.",
  "Your future self is watching. Make them proud. Build the life they're counting on.",
  "Progress is not linear. Trust the process. The breakthrough is coming.",
  "You are stronger than yesterday. Keep pushing. The edge is where growth happens."
];

// Exercise tips
const exerciseTips = [
  "5-min stretch: Shoulder rolls 10x, neck circles, touch toes. Blood flow = brain flow.",
  "Take the stairs today. Every step counts. Movement creates energy.",
  "Desk push-ups: 10 reps against desk. Upper body wake-up. Do it now.",
  "Walk while you think. 10 minutes outside resets your whole nervous system.",
  "Hydrate first. 16oz water before coffee. Your cells will thank you.",
  "Box breathing: 4-4-4-4. Inhale, hold, exhale, hold. Calm the mind in 2 minutes.",
  "Stand up every hour. Set a timer. Sitting is the new smoking."
];

// Family reminders
const familyReminders = [
  "Text someone you love. Takes 10 seconds, lasts all day. Connection is wealth.",
  "Call your person. Even 2 minutes matters more than any deal you'll close today.",
  "Show up present tonight. Phone down at dinner. Eyes up. They notice.",
  "Small moments with family > big moments anywhere else. Prioritize.",
  "Your kids notice when you show up. Be there. Time is the only asset you can't buy back.",
  "Ask someone how their day was. Actually listen. That's the good stuff.",
  "Hug your people. Physical connection reduces cortisol. Science-backed love."
];

// Self reminders
const selfReminders = [
  "You can't pour from an empty cup. Take 10 minutes for YOU today. Non-negotiable.",
  "Protect your energy. Say no to what drains you. Boundaries are business strategy.",
  "Progress > perfection. You are enough right now. Don't wait to be happy.",
  "Breathe. You are doing more than you realize. Give yourself credit.",
  "Rest is part of the grind. Schedule it like a meeting. Recovery = performance.",
  "You are not your output. Your worth is inherent. Remember that.",
  "Meditate for 5 minutes. Clear the cache. Your mind is a browser — refresh it."
];

// Money missions
const moneyMissions = [
  "One restaurant signing = $3,500 + $250/mo. Who are YOU calling today? Pick up the phone.",
  "Follow up hot. Mt Fuji was interested. Strike while the iron is hot. Time kills deals.",
  "Check your pipeline. Any leads stuck? Push them forward. Momentum beats perfection.",
  "Revenue solves problems. Focus on the next dollar, not the next problem. Action > anxiety.",
  "Your automation works while you sleep. Let n8n handle the follow-ups. You handle the closes.",
  "SyBridge is a real business. Treat it like one. Show up professional. Close like you mean it.",
  "Every no is data. Adjust. The market is telling you something. Listen and iterate."
];

// Science/AI facts
const scienceFacts = [
  "AI FACT: Claude 3 Opus can process 200K tokens (≈500 pages) in one go. Context is the new compute.",
  "SCIENCE: Neuroplasticity means your brain rewires itself at ANY age. You can learn anything.",
  "AI FACT: GPT-4o processes audio, vision, and text simultaneously. Multimodal is the future.",
  "SCIENCE: Dopamine spikes from completion, not pursuit. Finish tasks to feel good."
];

// Stoic/mindfulness teachings
const stoicTeachings = [
  "STOIC: 'You have power over your mind — not outside events. Realize this, and you will find strength.' — Marcus Aurelius",
  "MINDFULNESS: The present moment is all you ever have. The past is memory, the future is imagination. Be here now.",
  "STOIC: 'It is not things that disturb us, but our interpretation of things.' — Epictetus. Reframe the obstacle.",
  "MINDFULNESS: Equanimity = maintaining calm regardless of external circumstances. That is true power."
];

// Daily picks
const encouragement = encouragements[dayOfWeek % encouragements.length];
const exercise = exerciseTips[dayOfWeek % exerciseTips.length];
const family = familyReminders[dayOfWeek % familyReminders.length];
const selfCare = selfReminders[dayOfWeek % selfReminders.length];
const money = moneyMissions[dayOfWeek % moneyMissions.length];
const science = scienceFacts[dayOfWeek % scienceFacts.length];
const stoic = stoicTeachings[dayOfWeek % stoicTeachings.length];

return [{ json: {
  dayName,
  encouragement,
  exercise,
  family,
  selfCare,
  money,
  science,
  stoic
}}];

// Get CRM data from embedded summary
const crm = {
  total_leads: 4,
  new_leads: 4,
  hot_leads: 4,
  contacted: 0,
  top_leads: [
    { name: "Vinos", score: 88, category: "Pizza/Brewpub" },
    { name: "Does Eat Place", score: 85, category: "Steakhouse" },
    { name: "Riverfront Steakhouse", score: 82, category: "Steakhouse" },
    { name: "Mt Fuji", score: 80, category: "Sushi/Japanese" }
  ]
};

return [{ json: crm }];

// Build the full briefing
const weather = $input.all()[0].json.data || 'Weather unavailable';
const content = $input.all()[1].json;
const crm = $input.all()[2].json;

const message = `☀️ SOL MORNING BRIEFING

📅 ${content.dayName}
🌤️ ${weather}

💰 MONEY MISSION
${content.money}

📊 SYBRIDGE PIPELINE
• Total Leads: ${crm.total_leads}
• Hot Leads (80+): ${crm.hot_leads}
• New: ${crm.new_leads}
• Contacted: ${crm.contacted}

🔥 TOP LEADS
${crm.top_leads.map(l => `• ${l.name} (${l.score}) — ${l.category}`).join('\n')}

💪 EXERCISE TIP
${content.exercise}

👨‍👩‍👧‍👦 FAMILY
${content.family}

🧘 SELF
${content.selfCare}

🧠 SCIENCE / AI
${content.science}

🕊️ STOIC / MINDFULNESS
${content.stoic}

🔥 WORDS
${content.encouragement}

🔗 QUICK LINKS
• n8n: http://localhost:5678
• Outreach: ACTIVE & RUNNING
• CRM: ${crm.total_leads} leads ready

— SOL 🛰️`;

return [{ json: { message, subject: `SOL Briefing — ${content.dayName}` } }];
